mapper.select:
select count(1) from home_sections
and deleted = false
and section_type = #{sectionType}

select id, section_type, title, summary, hot_score, sort_no, display_status, created_at, updated_at, created_by, updated_by, deleted
from home_sections

  and deleted = false

    and section_type = #{sectionType}


order by sort_no asc, id asc
limit #{pageSize} offset #{offset}

mapper.update:
update home_sections
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where id = #{id}
  and deleted = false
